import Vue from 'vue';
import VueRouter from 'vue-router';
import HomeView from '../views/HomeView.vue'; // 1. Importe a nova view
import MenuView from '../views/MenuView.vue';
import PedidosView from '../views/PedidosView.vue';
import ConfiguracaoPedidoView from '../views/ConfiguracaoPedidoView.vue';

Vue.use(VueRouter);

const routes = [
  {
    path: '/',
    name: 'home',
    component: HomeView // 2. Defina ela como a página inicial
  },
  {
    path: '/menu',
    name: 'menu',
    component: MenuView
  },
  {
    path: '/configuracao',
    name: 'configuracao',
    component: ConfiguracaoPedidoView
  },
  {
    path: '/pedidos',
    name: 'pedidos',
    component: PedidosView
  }
];

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
});

export default router;
